def longest_palindromic_subsequence_dp(s, k):
    n = len(s)
    dp = [[0] * n for _ in range(n)]
    for i in range(n - 1, -1, -1):
        for j in range(i, n):
            if i == j:
                dp[i][j] = 1
            elif s[i] == s[j]:
                dp[i][j] = 2 + dp[i + 1][j - 1] if i + 1 <= j - 1 else 2
            else:
                if k > 0:
                    dp[i][j] = 1 + max(dp[i + 1][j], dp[i][j - 1])
                else:
                    dp[i][j] = 0
    max_length = 0
    for i in range(n):
        for j in range(i, n):
            if dp[i][j] + k >= j - i + 1:
                max_length = max(max_length, j - i + 1)
    return max_length

