def longest_palindromic_subsequence(s, k):
    def helper(s, left, right, k, memo):
        if (left, right, k) in memo:
            return memo[(left, right, k)]
        if left > right:
            return 0
        if left == right:
            return 1
        if s[left] == s[right]:
            result = helper(s, left + 1, right - 1, k, memo) + 2
        else:
            if k > 0:
                result = max(helper(s, left + 1, right, k - 1, memo), helper(s, left, right - 1, k - 1, memo)) + 1
            else:
                result = 0
