def canConvertString(s, k):
    if len(s) % k != 0:
        return -1
    target = s * (k // len(s)) + s[:k % len(s)]
    for i in range(len(s)):
        if ord(target[i]) - ord(s[i]) not in [0, 1]:
            return -1
    return len(set(target)) - 1

def findAndReplaceString(s, k):
    if k == 0:
        return s
    result = ""
    for i in range(len(s)):
        if i % k == 0:
            result += chr((ord(s[i]) - ord('a') + 1) % 26 + ord('a'))
        else:
            result += s[i]
    return result

