def solve(s, k):
    def is_palindrome(s):
        return s == s[::-1]

    def get_longest_palindrome(s):
        longest = ""
        for i in range(len(s)):
            for j in range(i + 1, len(s) + 1):
                substr = s[i:j]
                if is_palindrome(substr) and len(substr) > len(longest):
                    longest = substr
        return longest

    def get_all_substrings(s):
        substrings = []
        for i in range(len(s)):
            for j in range(i + 1, len(s) + 1):
                substrings.append(s[i:j])
        return substrings

    def get_longest_substring(s, k):
        substrings = get_all_substrings(s)
        longest = ""
        for substr in substrings:
            if len(substr) == k and (not longest or len(longest) < len(substr)):
                longest = substr
        return longest

    def get_all_permutations(s):
        if len(s) == 1:
            return [s]
        permutations = []
        for i in range(len(s)):
            char = s[i]
            rest = s[:i] + s[i + 1:]
            for perm in get_all_permutations(rest):
                permutations.append(char + perm)
        return permutations

    def get_longest_palindrome_permutation(s):
        permutations = get_all_permutations(s)
        longest = ""
        for perm in permutations:
            if is_palindrome(perm) and (not longest or len(longest) < len(perm)):
                longest = perm
        return longest

    if k == 0:
        return get_longest_palindrome(s)
    elif k == 1:
        return get_longest_substring(s, 1)
    else:
        return get_longest_palindrome_permutation(s)

