def convert_string(s, k):
    if k == 0 or k == len(s):
        return s
    rows = [''] * k
    index, step = 0, 1
    for char in s:
        rows[index] += char
        if index == 0:
            step = 1
        elif index == k - 1:
            step = -1
        index += step
    return ''.join(rows)

